const y=window.API_CONFIG?.BASE_URL||"/api";async function e(r,t){const o=new AbortController,s=setTimeout(()=>o.abort(),3e4);try{const n={"Content-Type":"application/json"},a=await fetch(`${y}${r}`,{method:"POST",credentials:"include",headers:n,body:JSON.stringify(t),signal:o.signal});if(!a.ok){const l=await a.text();let c;try{c=JSON.parse(l).error}catch{c=l}throw new Error(c||`Chyba serveru (${a.status})`)}const i=await a.json();if(!i.success)throw new Error(i.error||"Nezn\xE1m\xE1 chyba");return i.response}catch(n){throw n.name==="AbortError"?new Error("Po\u017Eadavek vypr\u0161el. Zkuste to pros\xEDm znovu."):(console.error(`API Error (${r}):`,n),n)}finally{clearTimeout(s)}}async function u(r,t=[]){return e("/crystal-ball",{question:r,history:t})}async function d(r,t,o="t\u0159\xEDkartov\xFD"){return e("/tarot",{question:r,cards:t,spreadType:o})}async function w({birthDate:r,birthTime:t,birthPlace:o,name:s}){return e("/natal-chart",{birthDate:r,birthTime:t,birthPlace:o,name:s})}async function p(r,t){return e("/synastry",{person1:r,person2:t})}async function f(r,t){return e("/horoscope",{sign:r,date:t})}async function h({emotion:r,intention:t,sign:o}){return e("/meditation",{emotion:r,intention:t,sign:o})}typeof window<"u"&&(window.GeminiService={askCrystalBall:u,readTarot:d,analyzeNatalChart:w,analyzeSynastry:p,getDailyHoroscope:f,generateMeditation:h,getDailyWisdom:(r,t,o)=>e("/daily-wisdom",{sign:r,moonPhase:t,lang:o})});async function m(r,t,o){return e("/daily-wisdom",{sign:r,moonPhase:t,lang:o})}export{w as analyzeNatalChart,p as analyzeSynastry,u as askCrystalBall,h as generateMeditation,f as getDailyHoroscope,m as getDailyWisdom,d as readTarot};
